sharedHelpers.makeFrame:
function makeFrame(overrides?: Partial<FrameState & { params: Partial<VisualParams> }>): FrameState {
  return {
    time: 1000,
    delta: 16,
    elapsed: 1000,
    width: 800,
    height: 600,
    params: { ...defaultParams, ...(overrides?.params ?? {}) },
    ...Object.fromEntries(Object.entries(overrides ?? {}).filter(([k]) => k !== 'params')),
  } as FrameState;
}

sharedHelpers.defaultParams:
const defaultParams: VisualParams = {
  paletteHue: 180, paletteSaturation: 0.5, cadence: 0.7, density: 0.6,
  motionAmplitude: 1.0, pointerDisturbance: 0, bassEnergy: 0, trebleEnergy: 0,
  curveSoftness: 0.5, structureComplexity: 0.5, noiseFrequency: 1.0,
  radialScale: 1.0, twistStrength: 1.0, fieldSpread: 1.0,
};

sharedHelpers.stdDev:
function stdDev(arr: Float32Array, offset: number, stride: number, count: number): number {
  if (count === 0) return 0;
  let sum = 0;
  for (let i = 0; i < count; i++) sum += arr[i * stride + offset];
  const mean = sum / count;
  let variance = 0;
  for (let i = 0; i < count; i++) {
    const d = arr[i * stride + offset] - mean;
    variance += d * d;
  }
  return Math.sqrt(variance / count);
}
